module top_module(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg q_reg;
wire obf_mux_out;
assign obf_mux_out = (SCE == 1'b1)? SCD : D;

always @ ( posedge CLK)
       begin
	     q_reg <= obf_mux_out;
       end

assign Q = q_reg;

endmodule
